import Vision
import AVFoundation

let initial = VNDetectedObjectObservation(boundingBox: CGRect(x: 0.4, y: 0.4, width: 0.2, height: 0.2))

let request = VNTrackObjectRequest(detectedObjectObservation: initial)
request.trackingLevel = .accurate

func handleFrame(_ buffer: CVPixelBuffer) {
    let handler = VNImageRequestHandler(cvPixelBuffer: buffer)
    try? handler.perform([request])

    if let result = request.results?.first as? VNDetectedObjectObservation {
        print("🎯 Position: \(result.boundingBox)")
    }
}

