import Vision
import UIKit

func featurePrint(from image: UIImage) -> VNFeaturePrintObservation? {
    let req = VNGenerateImageFeaturePrintRequest()
    let handler = VNImageRequestHandler(cgImage: image.cgImage!)
    try? handler.perform([req])
    return req.results?.first as? VNFeaturePrintObservation
}

let img1 = UIImage(named: "photo1")!
let img2 = UIImage(named: "photo2")!

if let f1 = featurePrint(from: img1), let f2 = featurePrint(from: img2) {
    var distance: Float = 0
    try? f1.computeDistance(&distance, to: f2)
    print("🔎 Ähnlichkeit: \(distance)")
}
